(function(){'use strict';const ERROR_PAGE='/111ceshi/error_page.php';const TIMEOUT_PAGE='/111ceshi/timeout_page.php';const TIMEOUT_DURATION=30000;const DEBUG_MODE=false;const activeRequests=new Map();function showError(code,title,message,details){if(DEBUG_MODE){console.error('[Error Handler]',code,title,message,details);return;}const params=new URLSearchParams({code:code,title:title,message:message,details:details||''});window.location.href=ERROR_PAGE+'?'+params.toString();}function showTimeout(message){if(DEBUG_MODE){console.warn('[Timeout Handler]',message);return;}const params=new URLSearchParams({message:message||'请求超时，请检查网络连接'});window.location.href=TIMEOUT_PAGE+'?'+params.toString();}function fetchWithTimeout(url,options={},timeout=TIMEOUT_DURATION){const controller=new AbortController();const{signal}=controller;const timeoutId=setTimeout(()=>{controller.abort();},timeout);activeRequests.set(url,{controller,timeoutId});return originalFetch(url,{...options,signal}).then(response=>{activeRequests.delete(url);clearTimeout(timeoutId);if(!response.ok){if(response.status===404){showError('404','页面未找到','请求的资源不存在或已被移除');}else if(response.status===403){showError('403','无权访问','您没有权限访问此资源');}else if(response.status===401){showError('401','未授权','请先登录');}else if(response.status>=500){showError('500','服务器错误','服务器开小差了，请稍后再试');}throw new Error(`HTTP error!status:${response.status}`);}return response;}).catch(error=>{activeRequests.delete(url);clearTimeout(timeoutId);if(error.name==='AbortError'){showTimeout('请求超时，请检查网络连接后重试');}else if(error.name==='TypeError'&&error.message.includes('fetch')){showTimeout('网络连接失败，请检查网络后重试');}else{console.error('[Fetch Error]',error);showError('ERROR','请求失败',error.message||'未知错误');}throw error;});}function xhrWithTimeout(url,options={}){return new Promise((resolve,reject)=>{const xhr=new XMLHttpRequest();const timeout=options.timeout||TIMEOUT_DURATION;let timedOut=false;const timeoutId=setTimeout(()=>{timedOut=true;xhr.abort();showTimeout('请求超时，请检查网络连接后重试');reject(new Error('Timeout'));},timeout);xhr.open(options.method||'GET',url,true);if(options.headers){Object.keys(options.headers).forEach(key=>{xhr.setRequestHeader(key,options.headers[key]);});}xhr.timeout=timeout;xhr.onload=function(){clearTimeout(timeoutId);if(timedOut)return;if(xhr.status>=200&&xhr.status<300){try{const data=JSON.parse(xhr.responseText);if(data.code===404){showError('404','资源未找到',data.message||'资源不存在');}else if(data.code===403){showError('403','无权访问',data.message||'没有权限');}resolve(data);}catch(e){resolve(xhr.responseText);}}else{if(xhr.status===404){showError('404','页面未找到','请求的资源不存在');}else if(xhr.status===403){showError('403','无权访问','没有访问权限');}else if(xhr.status>=500){showError('500','服务器错误','服务器内部错误');}reject(new Error(`HTTP ${xhr.status}`));}};xhr.onerror=function(){clearTimeout(timeoutId);if(timedOut)return;showTimeout('网络连接失败，请检查网络后重试');reject(new Error('Network error'));};xhr.ontimeout=function(){clearTimeout(timeoutId);showTimeout('请求超时，请检查网络连接后重试');reject(new Error('Timeout'));};xhr.send(options.body||null);});}window.addEventListener('error',function(event){if(event.filename&&event.filename.startsWith('chrome-extension://')){return;}if(DEBUG_MODE){console.error('[Global Error]',event.message,event.filename,event.lineno);return;}if(event.target&&event.target.tagName){const tagName=event.target.tagName.toLowerCase();if(['script','link','img'].includes(tagName)){console.warn(`[Resource Error] Failed to load ${tagName}:`,event.target.src||event.target.href);}}},true);window.addEventListener('unhandledrejection',function(event){if(DEBUG_MODE){console.warn('[Unhandled Rejection]',event.reason);return;}if(event.reason&&event.reason.message&&event.reason.message.includes('Abort')){return;}if(event.reason&&(event.reason.name==='TypeError'||event.reason.message.includes('fetch')||event.reason.message.includes('network')||event.reason.message.includes('timeout'))){showTimeout('网络请求失败，请检查连接后重试');}});window.addEventListener('beforeunload',function(){activeRequests.forEach(({controller,timeoutId})=>{controller.abort();clearTimeout(timeoutId);});activeRequests.clear();});const originalFetch=window.fetch;window.GlobalErrorHandler={fetch:fetchWithTimeout,xhr:xhrWithTimeout,showError:showError,showTimeout:showTimeout,setDebugMode:(mode)=>{DEBUG_MODE=mode;},originalFetch:originalFetch};window.fetch=function(...args){if(window.location.pathname.includes(ERROR_PAGE)||window.location.pathname.includes(TIMEOUT_PAGE)){return originalFetch.apply(this,args);}return fetchWithTimeout.apply(this,args);};if(DEBUG_MODE){console.log('[Global Error Handler] Initialized');}})();